SELECT FROM km_knowledge_base WHERE is_deleted = 0
AND category = #{query.category}
AND (LOWER(name) LIKE CONCAT('%', LOWER(#{query.q}), '%') OR LOWER(IFNULL(description, '')) LIKE CONCAT('%', LOWER(#{query.q}), '%'))
ORDER BY created_at DESC LIMIT #{offset}, #{query.pageSize}

